static const int SPELLS_N = 957;

inline const SpellRow* spell_info(unsigned id) {
    int lo = 0, hi = SPELLS_N - 1;
    while (lo <= hi) { int mid = (lo + hi) >> 1;
        if (SPELLS[mid].id == id) return &SPELLS[mid];
        if (SPELLS[mid].id < id) lo = mid + 1; else hi = mid - 1; }
    return 0;
}

